<template>
	<view class="page-container">
		<!-- жңӘзҷ»еҪ•зҠ¶жҖҒ -->
		<view class="login-box" v-if="!userInfo._id">
			<view class="login-content">
				<view class="login-title">ж¬ўиҝҺдҪҝз”Ёе®Үйқ’йқ’е®ҮеӨҮеҝҳеҪ•</view>
				<view class="login-desc">зҷ»еҪ•еҗҺеҸҜд»Ҙи®°еҪ•дҪ зҡ„иҝҪжҳҹеҺҶзЁӢпјҢиҝҳжңүжӣҙеӨҡ surprises зӯүдҪ жқҘеҸ‘зҺ°</view>
				<button class="login-btn" @click="getUserInfo">з«ӢеҚізҷ»еҪ•</button>
			</view>
		</view>
		
		<!-- е·Ізҷ»еҪ•зҠ¶жҖҒ -->
		<view class="profile-box" v-else>
			<!-- з”ЁжҲ·дҝЎжҒҜеҚЎзүҮ -->
			<view class="user-card">
				<image class="user-avatar" src="/static/userImg/baby.png" mode="aspectFill"></image>
				<view class="user-info">
					<view class="user-name">
                        <view class="user-nick-name" @click="editField('nickName')">{{userInfo.nickName || 'жқҜжқҜе„ҝ'}}</view>
                        <view class="archive-value" @click="editField('loveType')">{{profileData.loveType || 'жңӘи®ҫзҪ®'}}</view>
                        <view class="archive-value" @click="editField('joinTime')">е…Ҙеқ‘ж—¶й—ҙпјҡ{{profileData.joinTime || 'жңӘи®ҫзҪ®'}}{{joinDays > 0 ? `пјҲ${joinDays}еӨ©пјү` : ''}}</view>
                    </view>
				</view>
                
			</view>
			
			<!-- еҲ·ж–°жҢүй’® -->
			<view class="refresh-btn" @click="refreshUserInfo">
				<uni-icons type="refresh" size="20" color="#8b5cf6"></uni-icons>
				<text>еҲ·ж–°з”ЁжҲ·дҝЎжҒҜ</text>
			</view>
			
			
			
			<!-- еҠҹиғҪиҸңеҚ• -->
			<view class="menu-box">
				<view class="menu-item" @click="goToTodo">
					<view class="menu-icon">рҹ“қ</view>
					<view class="menu-text">жҲ‘зҡ„еҫ…еҠһ</view>
				</view>
				<view class="menu-item" @click="showMeetTypeDialog">
					<view class="menu-icon">рҹҺӨ</view>
					<view class="menu-text">зӮ№дә®еҸҢдәәи§Ғйқў</view>
				</view>
				<view class="menu-item" @click="goToPayRecord">
					<view class="menu-icon">рҹ’°</view>
					<view class="menu-text">и®°иҙҰ</view>
				</view>
				<view class="menu-item" @click="goToFootprint">
					<view class="menu-icon">рҹ—әпёҸ</view>
					<view class="menu-text">и¶іиҝ№</view>
				</view>
				<view class="menu-item" @click="goToSuggestion">
					<view class="menu-icon">рҹ’¬</view>
					<view class="menu-text">жқҜжқҜе„ҝдҝЎз®ұ</view>
				</view>
			</view>
			
			<!-- е…¶д»–дҝЎжҒҜ -->
			<view class="info-box">
				<view class="info-item" @click="goToConcertAdmin"  v-if="canManageConcert">
					<view class="info-text">жј”е”ұдјҡ/йҹід№җиҠӮз®ЎзҗҶ</view>
				</view>
				<view class="info-item" @click="showAbout">
					<view class="info-text">е…ідәҺжҲ‘д»¬</view>
				</view>
			</view>
			
			<!-- зүҲжң¬еҸ· -->
			<view class="version">v19.27.69</view>
		</view>
	</view>
</template>

<script>
	import { hasConcertPermission } from '@/common/js/permission.js'
	
	export default {
		data() {
			return {
				userInfo: {},
				profileData: {
					joinTime: '',
					loveType: 'е®Үйқ’99',
					wxid: ''
				},
				meetCount: 0,
				firstMeetInfo: '',
				todoCount: 0,
				joinDays: 0, // е…Ҙеқ‘еӨ©ж•°
				canManageConcert: false, // жҳҜеҗҰжңүжј”е”ұдјҡз®ЎзҗҶжқғйҷҗ
				// зј–иҫ‘иЎЁеҚ•ж•°жҚ®
				editForm: {
					nickName: '',
					startTime: '',
					loveType: '',
					wxid: ''
				}
			}
		},
		onShareAppMessage: function () {
		   return {
		     title: 'е®Үйқ’йқ’е®Үе…ЁиӮҜе®ҡ',
		     path: '/pages/rili/rili'
		   }
		 },
		 onShareTimeline: function () {
		    return {
		      title: 'е®Үйқ’йқ’е®Үе…ЁиӮҜе®ҡ'
		    }
		  },
		onShow() {
			const userInfo = uni.getStorageSync('userInfo')
			if (userInfo) {
				this.userInfo = JSON.parse(userInfo)
				// жЈҖжҹҘжј”е”ұдјҡз®ЎзҗҶжқғйҷҗ
				this.canManageConcert = hasConcertPermission(this.userInfo, 'manage')
				if (this.userInfo._id) {
					this.getUserStats()
				} else {
					this.getUserInfo()
				}
			} else {
				this.getUserInfo()
			}
		},
		methods: {
			getUserInfo() {
				const _this = this
				uni.getUserProfile({
					desc: 'з”ЁдәҺе®Ңе–„дјҡе‘ҳиө„ж–ҷ',
					success: (result) => {
						_this.userInfo = result.userInfo
						_this.wxLogin()
					},
					fail: () => {
						
						uni.hideLoading()
						uni.showModal({
							content: 'иҺ·еҸ–з”ЁжҲ·дҝЎжҒҜеӨұиҙҘ',
							showCancel: false
						})
					}
				})
			},
			wxLogin() {
				const _this = this
				uni.showLoading({ title: 'еҠ иҪҪдёӯ' })
				uni.login({
					provider: 'weixin',
					success: (res) => {
						if (res.code) {
							uniCloud.callFunction({
								name: 'user',
								data: {
									action: 'code2Session',
									js_code: res.code,
									user_info: _this.userInfo
								},
								success: (res) => {
									uni.hideLoading()
									// жЈҖжҹҘжҳҜеҗҰиў«зҰҒжӯўзҷ»еҪ•
									if (res.result.status === -3) {
										uni.showModal({
											content: res.result.msg || 'иҜҘз”ЁжҲ·е·Іиў«зҰҒжӯўзҷ»еҪ•',
											showCancel: false
										})
										return
									}
									
									if (res.result.result && res.result.result.result && res.result.result.result._id) {
										uni.setStorageSync('userInfo', JSON.stringify(res.result.result.result))
										_this.userInfo = res.result.result.result
										_this.getUserStats()
									}
									
								},
								fail: (err) => {
									uni.hideLoading()
									console.log('дә‘еҮҪж•°и°ғз”ЁеӨұиҙҘ', err)
									uni.showModal({
										content: 'зҷ»еҪ•еӨұиҙҘпјҢиҜ·йҮҚиҜ•',
										showCancel: false
									})
								}
							})
						}
					}
				})
			},
			getUserStats() {
				// иҺ·еҸ–ж¶Ҳиҙ№и®°еҪ•дёӯзҡ„йҹід№җиҠӮеңәж¬Ў
				console.log('еҪ“еүҚз”ЁжҲ·ID:', this.userInfo._id)
				
				
						
				// иҺ·еҸ–з”ЁжҲ·иҜҰз»ҶдҝЎжҒҜпјҲеҢ…жӢ¬ startTime е’Ң loveTypeпјү
				uniCloud.callFunction({
					name: 'user',
					data: {
						action: 'getUser',
						open_id: this.userInfo.mp_wx_openid
					},
					success: (res) => {
						if (res.result) {
							this.profileData.joinTime = res.result.startTime || ''
							this.profileData.loveType = res.result.loveType || 'е®Үйқ’99'
							this.profileData.wxid = res.result.wxid || ''
							
							// и®Ўз®—е…Ҙеқ‘еӨ©ж•°
							if (res.result.startTime) {
								this.calculateJoinDays(res.result.startTime)
							}
						}
					}
				})
			},
			// и®Ўз®—е…Ҙеқ‘еӨ©ж•°
			calculateJoinDays(startTime) {
				if (!startTime) {
					this.joinDays = 0
					return
				}
				
				try {
					const startDate = new Date(startTime.replace(/-/g, '/'))
					const now = new Date()
					
					// и®Ўз®—еӨ©ж•°е·®
					const diffTime = now.getTime() - startDate.getTime()
					const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24))
					
					this.joinDays = diffDays >= 0 ? diffDays : 0
				} catch (e) {
					console.error('и®Ўз®—е…Ҙеқ‘еӨ©ж•°еӨұиҙҘ:', e)
					this.joinDays = 0
				}
			},
			editProfile() {
				this.showEditDialog()
			},
			// зј–иҫ‘еҚ•дёӘеӯ—ж®ө
			editField(field) {
				let title = ''
				let currentValue = ''
				let placeholder = ''
				
				switch(field) {
					case 'nickName':
						title = ''
						currentValue = this.userInfo.nickName || ''
						placeholder = 'иҜ·иҫ“е…Ҙжҳөз§°'
						break
					case 'loveType':
						title = 'дҪ зҡ„еұһжҖ§'
						currentValue = this.profileData.loveType || ''
						placeholder = 'иҜ·иҫ“е…ҘеұһжҖ§'
						break
					case 'joinTime':
						title = 'е…Ҙеқ‘ж—¶й—ҙ'
						currentValue = this.profileData.joinTime || ''
						placeholder = 'иҜ·иҫ“е…Ҙе…Ҙеқ‘ж—¶й—ҙпјҢеҰӮпјҡ2020-01-01'
						break
				}
				
				uni.showModal({
					title: title,
					editable: true,
					placeholderText: placeholder,
					content: currentValue,
					success: (res) => {
						if (res.confirm && res.content) {
							const newValue = res.content.trim()
							if (field === 'nickName') {
								this.updateUserInfo(newValue, undefined, undefined, undefined)
							} else if (field === 'loveType') {
								this.updateUserInfo(undefined, undefined, newValue, undefined)
							} else if (field === 'joinTime') {
								this.updateUserInfo(undefined, newValue, undefined, undefined)
							}
						}
					}
				})
			},
			showEditDialog() {
				// еҲқе§ӢеҢ–зј–иҫ‘иЎЁеҚ•
				this.editForm = {
					nickName: this.userInfo.nickName || '',
					startTime: this.profileData.joinTime || '',
					loveType: this.profileData.loveType || 'е®Үйқ’99',
					wxid: this.profileData.wxid || ''
				}
						
				this.openEditPage()
			},
			openEditPage() {
				// и·іиҪ¬еҲ°зј–иҫ‘йЎөйқў
				uni.navigateTo({
					url: `/pages/profile/edit?nickName=${encodeURIComponent(this.editForm.nickName)}&startTime=${encodeURIComponent(this.editForm.startTime)}&loveType=${encodeURIComponent(this.editForm.loveType)}&wxid=${encodeURIComponent(this.editForm.wxid)}`
				})
			},
			updateUserInfo(newNickName, newStartTime, newLoveType, newWxid) {
				uni.showLoading({ title: 'дҝқеӯҳдёӯ...' })
				uniCloud.callFunction({
					name: 'user',
					data: {
						action: 'update',
						_id: this.userInfo._id,
						open_id: this.userInfo.mp_wx_openid,
						user_info: {
							nickName: newNickName || this.userInfo.nickName,
							avatarUrl: '/static/userImg/baby.png'
						},
						startTime: newStartTime !== undefined ? newStartTime : this.profileData.joinTime,
						loveType: newLoveType !== undefined ? newLoveType : this.profileData.loveType,
						wxid: newWxid !== undefined ? newWxid : this.profileData.wxid
					}
				}).then((res) => {
					uni.hideLoading()
					if (res.result) {
						// жӣҙж–°жң¬ең°ж•°жҚ®
						if (newNickName) {
							this.userInfo.nickName = newNickName
						}
						if (newStartTime !== undefined) {
							this.profileData.joinTime = newStartTime
						}
						if (newLoveType !== undefined) {
							this.profileData.loveType = newLoveType
						}
						if (newWxid !== undefined) {
							this.profileData.wxid = newWxid
						}
											
						// жӣҙж–°жң¬ең°еӯҳеӮЁ
						const userInfo = uni.getStorageSync('userInfo')
						if (userInfo) {
							const userObj = JSON.parse(userInfo)
							if (newNickName) userObj.nickName = newNickName
							if (newStartTime !== undefined) userObj.startTime = newStartTime
							if (newLoveType !== undefined) userObj.loveType = newLoveType
							if (newWxid !== undefined) userObj.wxid = newWxid
							uni.setStorageSync('userInfo', JSON.stringify(userObj))
						}
											
						uni.showModal({
							content: 'жӣҙж–°жҲҗеҠҹ',
							showCancel: false
						})
					}
				}).catch((err) => {
					uni.hideLoading()
					uni.showModal({
						content: `жӣҙж–°еӨұиҙҘпјҡ${err.message}`,
						showCancel: false
					})
				})
			},
			// еҲ·ж–°з”ЁжҲ·дҝЎжҒҜ
			refreshUserInfo() {
				uni.showLoading({ title: 'еҲ·ж–°дёӯ...' })
				
				// и°ғз”Ёдә‘еҮҪж•°иҺ·еҸ–жңҖж–°з”ЁжҲ·дҝЎжҒҜ
				uniCloud.callFunction({
					name: 'user',
					data: {
						action: 'getUser',
						open_id: this.userInfo.mp_wx_openid
					}
				}).then((res) => {
					uni.hideLoading()
					if (res.result && res.result.mp_wx_openid) {
						const userData = res.result
						
						// жӣҙж–°жң¬ең° userInfo
						this.userInfo = userData

						//жё…йҷӨжң¬ең°зј“еӯҳ
						uni.removeStorageSync('userInfo')
						
						// жӣҙж–° profileData
						uni.setStorageSync('userInfo', JSON.stringify(userData))
								
						
						// йҮҚж–°жЈҖжҹҘжқғйҷҗ
						this.canManageConcert = hasConcertPermission(this.userInfo, 'manage')
						
						// йҮҚж–°иҺ·еҸ–з»ҹи®Ўж•°жҚ®
						this.getUserStats()
						
						uni.showToast({
							title: 'еҲ·ж–°жҲҗеҠҹ',
							icon: 'success'
						})
					} else {
						uni.showToast({
							title: 'иҺ·еҸ–з”ЁжҲ·дҝЎжҒҜеӨұиҙҘ',
							icon: 'none'
						})
					}
				}).catch((err) => {
					uni.hideLoading()
					console.error('еҲ·ж–°з”ЁжҲ·дҝЎжҒҜеӨұиҙҘ:', err)
					uni.showToast({
						title: 'еҲ·ж–°еӨұиҙҘ',
						icon: 'none'
					})
				})
			},
			goToTodo() {
				uni.navigateTo({
					url: '/pages/myTodo/myTodo'
				})
			},
			showMeetTypeDialog() {
                // еҸҢдәәи§Ғйқў - и·іиҪ¬еҲ°зҺ°жңүзҡ„meetйЎөйқў
							this.goToMeet()
				// uni.showActionSheet({
				// 	itemList: ['еҸҢдәәи§Ғйқў', 'еҚ•дәәи§Ғйқў'],
				// 	success: (res) => {
				// 		if (res.tapIndex === 0) {
				// 			// еҸҢдәәи§Ғйқў - и·іиҪ¬еҲ°зҺ°жңүзҡ„meetйЎөйқў
				// 			this.goToMeet()
				// 		} else if (res.tapIndex === 1) {
				// 			// еҚ•дәәи§Ғйқў - и·іиҪ¬еҲ°ж–°зҡ„еҚ•дәәи§ҒйқўйЎөйқў
				// 			this.goToSingleMeet()
				// 		}
				// 	}
				// })
			},
			goToMeet() {
				uni.navigateTo({
					url: '/pages/meet/meet'
				})
			},
			goToSingleMeet() {
				uni.navigateTo({
					url: '/pages/meet/singleMeet'
				})
			},
			goToPayRecord() {
				uni.navigateTo({
					url: '/pages/payRecord/record'
				})
			},
			goToConcertAdmin() {
				uni.navigateTo({
					url: '/pages/concert/admin'
				})
			},
			goToSuggestion() {
				uni.navigateTo({
					url: '/pages/myTodo/suggestion'
				})
			},
			goToFootprint() {
				uni.navigateTo({
					url: '/pages/footprint/footprint'
				})
			},
			
			showAbout() {
				uni.navigateTo({
					url: '/pages/profile/about'
				})
			}
		}
	}
</script>

<style lang="scss">
.page-container {
	min-height: 100vh;
	background: linear-gradient(180deg, #cff8f5 0%, #e6cffc 100%);
    padding: 1px
}

// жңӘзҷ»еҪ•зҠ¶жҖҒ
.login-box {
	min-height: 100vh;
	display: flex;
	align-items: center;
	justify-content: center;
	padding: 40rpx;
	
	.login-content {
		background: #fff;
		border-radius: 32rpx;
		padding: 80rpx 60rpx;
		text-align: center;
		box-shadow: 0 8rpx 32rpx rgba(0, 0, 0, 0.1);
		
		.login-avatar {
			font-size: 120rpx;
			margin-bottom: 32rpx;
		}
		
		.login-title {
			font-size: 40rpx;
			font-weight: bold;
			color: #333;
			margin-bottom: 16rpx;
		}
		
		.login-desc {
			font-size: 28rpx;
			color: #999;
			margin-bottom: 48rpx;
		}
		
		.login-btn {
			width: 100%;
			height: 88rpx;
			background: linear-gradient(135deg, #c62828 0%, #d32f2f 100%);
			color: #fff;
			border-radius: 44rpx;
			font-size: 32rpx;
			border: none;
		}
	}
}

// е·Ізҷ»еҪ•зҠ¶жҖҒ
.profile-box {
	padding: 0 30rpx 40rpx;
}

// з”ЁжҲ·дҝЎжҒҜеҚЎзүҮ
.user-card {
	background: linear-gradient(135deg, #d49ff8 0%, #a9fafa 100%);
	border-radius: 24rpx;
	padding: 40rpx;
	margin: 20rpx 0;
	display: flex;
	align-items: center;
	box-shadow: 0 8rpx 24rpx rgba(198, 40, 40, 0.3);
	
	.user-avatar {
		width: 120rpx;
		height: 120rpx;
		border-radius: 50%;
		background: rgba(255, 255, 255, 0.2);
		margin-right: 32rpx;
		border: 4rpx solid rgba(255, 255, 255, 0.5);
	}
	
	.user-info {
		flex: 1;
		display: flex;
		align-items: center;
		justify-content: space-between;
        .user-name{
			color: #fff;
			
			.archive-value {
				font-size: 28rpx;
				color: #fff;
				margin-top: 8rpx;
				cursor: pointer;
				transition: opacity 0.3s;
				
				&:active {
					opacity: 0.7;
				}
			}
        }
		
		.user-nick-name {
			font-size: 40rpx;
			font-weight: bold;
			cursor: pointer;
			transition: opacity 0.3s;
			
			&:active {
				opacity: 0.7;
			}
		}
		
		.user-edit-btn {
			background: rgba(255, 255, 255, 0.2);
			color: #fddb40;
			padding: 16rpx 32rpx;
			border-radius: 32rpx;
			font-size: 28rpx;
		}
	}
}

// жЎЈжЎҲеҚЎзүҮ
.archive-box {
	background: #fff;
	border-radius: 24rpx;
	padding: 32rpx;
	margin: 20rpx 0;
	box-shadow: 0 4rpx 16rpx rgba(0, 0, 0, 0.08);
	
	.archive-title {
		display: flex;
		align-items: center;
		margin-bottom: 24rpx;
		font-size: 32rpx;
		font-weight: bold;
		color: #333;
		
		.archive-title-bar {
			width: 6rpx;
			height: 32rpx;
			background: #c62828;
			border-radius: 3rpx;
			margin-right: 12rpx;
		}
	}
	
	.archive-content {
		.archive-item {
			background: #fff8e1;
			border-radius: 16rpx;
			padding: 24rpx;
			margin-bottom: 16rpx;
			
			&.full-width {
				margin-bottom: 0;
			}
			
			.archive-label {
				font-size: 24rpx;
				color: #666;
